        const cukContainer = document.getElementById('cuckold-container');
        cukContainer.innerHTML = '';

        if(cuckoldRaw && cuckoldRaw !== '暂无目标') {
            const targets = cuckoldRaw.split('/');
            targets.forEach(t => {
                const parts = t.split(':');
                if(parts.length === 2) {
                    const name = parts[0].trim();
                    const progress = parts[1].replace('%','').trim();
                    cukContainer.innerHTML += `
                    <div class="cuckold-row">
                        <div class="cuckold-name">${name}</div>
                        <div class="progress-bar-bg">
                            <div class="progress-bar-fill" style="width: ${progress}%;"></div>
                        </div>
                        <div class="cuckold-val">${progress}%</div>
                    </div>`;
                }
            });
        } else {
            cukContainer.innerHTML = '<span style="color:var(--gl-muted);font-size:0.85rem;">暂无有效侵蚀目标</span>';
        }

        // =======================
        // 2. 获取MVU数据并渲染
        // =======================
        const hasAllVars = typeof getAllVariables === 'function';
        const hasLodash = typeof _ !== 'undefined' && typeof _.get === 'function';

        if (hasAllVars && hasLodash) {
            const vars = getAllVariables();
            // 基础信息填充
            document.getElementById('mvu-date').innerText = _.get(vars, '日期', '获取失败');
            document.getElementById('mvu-time').innerText = _.get(vars, '时间', '获取失败');
            document.getElementById('mvu-location').innerText = _.get(vars, '所在地点', '未知');

            // 渲染人物字典
            // 在您的Schema中，人物字典直接存在根级别的 '人物关系'，而不是 'stat_data'。
            // 依据Tavern MVU架构，外部通常会嵌套一层，如果直接存，我们就直接取。
            // 注意：具体路径视系统实际挂载而定，下方采用安全回退机制尝试拉取。
            let charObj = _.get(vars, '人物关系', null) || _.get(vars, 'stat_data.人物关系', {});
            const charContainer = document.getElementById('mvu-characters-list');
            charContainer.innerHTML = '';

            const charNames = Object.keys(charObj);
            if(charNames.length > 0) {
                charNames.forEach(name => {
                    const data = charObj[name];
                    const aff = _.get(data, '亲和度', 0);
                    const threat = _.get(data, '威胁度', 0);
                    const unbal = _.get(data, '失衡度', 0);
                    const rep = _.get(data, '公开印象', '暂无定评');

                    const cardHtml = `
                    <div class="char-card" onclick="this.classList.toggle('expanded')">
                        <div class="char-header">
                            <span>◈ ${name}</span>
                            <span style="font-size:0.8rem; color:var(--gl-gold);">亲和: ${aff}</span>
                        </div>
                        <div class="char-expand-area">
                            <div><span style="color:var(--gl-muted)">威胁度:</span> ${threat}/100</div>
                            <div><span style="color:var(--gl-muted)">失衡度:</span> ${unbal}/100</div>
                            <div style="grid-column: 1 / -1;"><span style="color:var(--gl-muted)">综合印象:</span> ${rep}</div>
                        </div>
                    </div>`;
                    charContainer.innerHTML += cardHtml;
                });
            } else {
                charContainer.innerHTML = '<div style="color:var(--gl-muted);font-size:12px;text-align:center;">当前图谱暂无收录角色数据</div>';
            }
        }

        // =======================
        // 3. 技能框交互逻辑
        // =======================
        let currentSkill = '';
        window.openSkill = function(skillName) {
            const box = document.getElementById('skill-input-box');
            const pre = document.getElementById('active-skill-prefix');
            box.style.display = 'flex';
            currentSkill = skillName;
            pre.innerText = `【${skillName}+`;
            document.getElementById('skill-args').focus();
        };

        window.sendSkillCommand = function() {
            const args = document.getElementById('skill-args').value.trim();
            if(!args) return;
            // 组合最终发送字符串，遵循格式 【技能名+对象,场景,指令】
            const finalString = `【${currentSkill}+${args}】`;

            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + finalString + ' | /trigger');
                // 发送后清空并隐藏
                document.getElementById('skill-args').value = '';
                document.getElementById('skill-input-box').style.display = 'none';
            } else {
                alert('系统未连接到指令执行端(酒馆助手宏未激活)，当前模拟发送：' + finalString);
            }
        };

        // 按回车键触发发送
        document.getElementById('skill-args').addEventListener('keypress', function(e) {
            if(e.key === 'Enter') {
                sendSkillCommand();
            }
        });
    })();
</script>
