    (function(){
        // 1. 解析生成 NTR 侵蚀度 (绿化度)
        const cuckoldRaw = document.getElementById('cuckold-container').getAttribute('data-raw');
        const cukContainer = document.getElementById('cuckold-container');
        cukContainer.innerHTML = '';

        if(cuckoldRaw && cuckoldRaw !== '暂无目标') {
            const targets = cuckoldRaw.split('/');
            targets.forEach(t => {
                const parts = t.split(':');
                if(parts.length === 2) {
                    const name = parts[0].trim();
                    const progress = parts[1].replace('%','').trim();
                    cukContainer.innerHTML += `
                    <div class="ntr-row">
                        <div class="ntr-target">${name}</div>
                        <div class="ntr-bar-wrap">
                            <div class="ntr-bar-fill" style="width: ${progress}%;"></div>
                        </div>
                        <div class="ntr-percent">${progress}%</div>
                    </div>`;
                }
            });
        } else {
            cukContainer.innerHTML = '<span style="color:var(--sys-text-dim);font-size:0.85rem;">[ 暂未锁定侵蚀目标 ]</span>';
        }

        // 2. 对接Zod MVU静态参数
        const hasAllVars = typeof getAllVariables === 'function';
        const hasLodash = typeof _ !== 'undefined' && typeof _.get === 'function';

        if (hasAllVars && hasLodash) {
            const vars = getAllVariables();

            // 时空坐标
            const dateStr = _.get(vars, '日期', '获取失败');
            const timeStr = _.get(vars, '时间', '');
            document.getElementById('mvu-date').innerText = dateStr + ' ' + timeStr;
            document.getElementById('mvu-location').innerText = _.get(vars, '所在地点', '未知区域');

            // 渲染全息图谱
            let charObj = _.get(vars, '人物关系', null) || _.get(vars, 'stat_data.人物关系', {});
            const charContainer = document.getElementById('mvu-characters-list');
            charContainer.innerHTML = '';

            const charNames = Object.keys(charObj);
            if(charNames.length > 0) {
                charNames.forEach(name => {
                    const data = charObj[name];
                    const aff = _.get(data, '亲和度', 0);
                    const threat = _.get(data, '威胁度', 0);
                    const unbal = _.get(data, '失衡度', 0);
                    const rep = _.get(data, '公开印象', '暂无定评');

                    const colorAff = aff > 50 ? 'var(--sys-green)' : 'var(--sys-text)';

                    const cardHtml = `
                    <div class="cyber-char" onclick="this.classList.toggle('expanded')">
                        <div class="cyber-char-head">
                            <span>▶ ${name}</span>
                            <span style="font-size:0.8rem; color:${colorAff}; text-shadow:0 0 5px ${colorAff};">亲和: <span style="font-family:monospace;">${aff}</span></span>
                        </div>
                        <div class="cyber-char-body">
                            <div><span style="color:var(--sys-text-dim)">威胁警报: </span> <span style="color:var(--sys-red);font-weight:bold;">${threat}%</span></div>
                            <div><span style="color:var(--sys-text-dim)">失衡状态: </span> <span style="color:var(--sys-gold);font-weight:bold;">${unbal}%</span></div>
                            <div style="grid-column: 1 / -1;"><span style="color:var(--sys-text-dim)">外界定评: </span> <span style="color:#fff;">${rep}</span></div>
                        </div>
                    </div>`;
                    charContainer.innerHTML += cardHtml;
                });
            } else {
                charContainer.innerHTML = '<div style="color:var(--sys-text-dim);font-size:12px;text-align:center;width:100%;">[ 图谱内暂无活性目标 ]</div>';
            }
        }

        // 3. 终端注入控制 (四大技能修改)
        let currentSkill = '';
        const box = document.getElementById('skill-input-box');
        const pre = document.getElementById('active-skill-prefix');
        const argInput = document.getElementById('skill-args');

        window.openSkill = function(skillName) {
            if(box.style.display === 'flex' && currentSkill === skillName) {
                // 点击相同的按钮，折叠输入框
                box.style.display = 'none';
                return;
            }
            box.style.display = 'flex';
            currentSkill = skillName;
            pre.innerText = `【${skillName}+`;
            argInput.focus();

            // 增加一点高亮动画反馈
            box.style.boxShadow = '0 0 25px var(--sys-green)';
            setTimeout(() => { box.style.boxShadow = '0 0 15px var(--sys-green-dim)'; }, 300);
        };

        window.sendSkillCommand = function() {
            const args = argInput.value.trim();
            if(!args) return;
            // 最终格式：【聽令+参数】
            const finalString = `【${currentSkill}+${args}】`;

            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + finalString + ' | /trigger');
                argInput.value = '';
                box.style.display = 'none';
            } else {
                alert('终端尚未连接(未激活酒馆助手宏)。尝试发送指令：' + finalString);
            }
        };

        argInput.addEventListener('keypress', function(e) {
            if(e.key === 'Enter') sendSkillCommand();
        });
    })();
</script>
