    (function(){
        // ======================================
        // 核心一：四大技能快捷派发系统
        // ======================================
        let currentCmd = '';
        const drawer = document.getElementById('cmd-drawer');
        const prefix = document.getElementById('cmd-prefix');
        const argInput = document.getElementById('cmd-args');

        window.toggleCmd = function(cmdName) {
            if(drawer.classList.contains('active') && currentCmd === cmdName) {
                // 点击相同的关闭
                drawer.classList.remove('active');
                return;
            }
            drawer.classList.add('active');
            currentCmd = cmdName;
            prefix.innerText = `【${cmdName}+`;
            argInput.focus();
        };

        window.fireCmd = function() {
            const args = argInput.value.trim();
            if(!args) return;
            const finalCommand = `【${currentCmd}+${args}】`;

            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + finalCommand + ' | /trigger');
                argInput.value = '';
                drawer.classList.remove('active');
            } else {
                alert('环境未链接。拟发送指令：' + finalCommand);
            }
        };
        argInput.addEventListener('keypress', e => { if(e.key === 'Enter') fireCmd(); });

        // ======================================
        // 核心二：解析动态AI人物数据 + 融合MVU字典
        // ======================================
        const hasAllVars = typeof getAllVariables === 'function';
        const hasLodash = typeof _ !== 'undefined' && typeof _.get === 'function';

        let mvuVars = {};
        if (hasAllVars && hasLodash) mvuVars = getAllVariables();

        // 绑定基础MVU
        if(document.getElementById('zv-date')) {
            document.getElementById('zv-date').innerText = _.get(mvuVars, '日期', '未知');
            document.getElementById('zv-time').innerText = _.get(mvuVars, '时间', '');
            document.getElementById('zv-loc').innerText = _.get(mvuVars, '所在地点', '未知');
        }

        const rawChars = document.getElementById('char-render-zone').getAttribute('data-raw');
        const renderZone = document.getElementById('char-render-zone');
        renderZone.innerHTML = '';

        if(rawChars && rawChars.trim().length > 0) {
            // 切割所有角色 (用 / 分隔)
            const characters = rawChars.split(' / ');

            // 读取MVU中储存的人物好感等数据进行匹配
            const mvuDict = _.get(mvuVars, '人物关系', null) || _.get(mvuVars, 'stat_data.人物关系', {});

            characters.forEach(charRaw => {
                // 每人按逗号分割: 0名字, 1性别, 2衣着, 3状态, 4内心想法, 5绿化度
                const attrs = charRaw.split(',');
                if(attrs.length < 6) return; // 格式不符安全跳过

                const name = attrs[0].trim();
                const gender = attrs[1].trim(); // 男 / 女
                const clothes = attrs[2].trim().split(';'); // 衣着标签
                const stateDesc = attrs[3].trim();
                const thought = attrs[4].trim();
                const ntrDegree = parseInt(attrs[5].trim()) || 0;

                // 关联MVU数值
                const mData = mvuDict[name] || {};
                const affinity = _.get(mData, '亲和度', '未建档');
                const threat = _.get(mData, '威胁度', 0);
                const rep = _.get(mData, '公开印象', '无');

                // 性别样式区分
                const gIcon = gender === '男' ? '<span class="cc-gender-m">♂</span>' : '<span class="cc-gender-f">♀</span>';

                // 渲染衣着标签
                const clothesHtml = clothes.map(c => `<span class="cc-cloth-tag">${c.trim()}</span>`).join('');

                // 若为男性，专属添加绿化进度条
                let cuckoldHtml = '';
                if(gender === '男') {
                    cuckoldHtml = `
                    <div class="cuckold-meter">
                        <div class="cm-header"><span>☣ 绿化侵蚀度</span><span>${ntrDegree}%</span></div>
                        <div class="cm-track"><div class="cm-fill" style="width: ${ntrDegree}%;"></div></div>
                    </div>`;
                }

                const cardHtml = `
                <div class="char-card" onclick="this.classList.toggle('expanded')">
                    <div class="cc-head">
                        <span class="cc-name">${name} ${gIcon}</span>
                        <span class="cc-aff-badge">好感/亲和: ${affinity}</span>
                    </div>
                    <div class="cc-body">
                        <div class="cc-row">
                            <span class="cc-label">部位衣着:</span>
                            <div class="cc-clothes-wrap">${clothesHtml}</div>
                        </div>
                        <div class="cc-row">
                            <span class="cc-label">当前状态:</span>
                            <span style="color:#e2e8f0;">${stateDesc}</span>
                        </div>
                        <div class="cc-row" style="opacity:0.7; font-size:0.8rem;">
                            <span class="cc-label">威胁/印象:</span>
                            <span>威胁度 ${threat} | 世评: ${rep}</span>
                        </div>
                        <div class="cc-thought">
                            " ${thought} "
                        </div>
                        ${cuckoldHtml}
                    </div>
                </div>`;

                renderZone.innerHTML += cardHtml;
            });
        }
    })();
</script>
