    /* =========================================
       3. 人物全息琉璃卡片
    ========================================= */
    .char-engine-title {
        color: var(--eth-blue); font-size: 1rem; border-bottom: 1px solid rgba(96, 165, 250, 0.3);
        padding-bottom: 8px; margin-top: 5px; display: flex; justify-content: space-between;
