    .char-card:hover {
        border-color: var(--eth-blue);
        transform: translateY(-5px);
        box-shadow: 0 10px 25px rgba(96, 165, 250, 0.2), 0 0 15px rgba(192, 132, 252, 0.3);
    }

    /* 卡片底部的七彩点缀线 */
    .char-card::after {
        content: ""; position: absolute; bottom: 0; left: 0; right: 0;
        height: 2px;
        background: linear-gradient(90deg, #ff4b4b, #facc15, #4ade80, #60a5fa, #c084fc, #ff4b4b);
        background-size: 200% 100%;
        animation: gradient-flow 3s linear infinite;
        opacity: 0; transition: opacity 0.3s;
    }
    .char-card:hover::after, .char-card.expanded::after { opacity: 1; }

    .cc-head {
        padding: 14px 16px; display: flex; justify-content: space-between; align-items: center;
        background: rgba(0,0,0,0.25);
    }
    .cc-name { font-weight: 900; font-size: 1.1rem; color: #fff; display: flex; align-items: center; gap:8px;}

    .cc-gender-f { color: var(--eth-pink); font-size: 1.2rem; text-shadow: 0 0 8px rgba(244, 114, 182, 0.6); }
    .cc-gender-m { color: var(--eth-blue); font-size: 1.2rem; text-shadow: 0 0 8px rgba(96, 165, 250, 0.6); }

    /* 蓝紫渐变数值牌 */
    .cc-aff-badge {
        background: var(--bp-gradient); color: #fff;
        padding: 4px 10px; border-radius: 12px; font-size: 0.8rem; font-weight: bold;
        box-shadow: 0 2px 5px rgba(168, 85, 247, 0.4);
    }

    /* 展开细节容器 */
    .cc-body {
        max-height: 0; opacity: 0; overflow: hidden;
        transition: all 0.5s ease;
        padding: 0 16px; display: flex; flex-direction: column; gap: 10px;
    }
    .char-card.expanded .cc-body {
        max-height: 400px; opacity: 1; padding: 16px;
        background: rgba(0,0,0,0.1);
    }

    .cc-row { display: flex; gap: 10px; font-size: 0.85rem; align-items: flex-start;}
    .cc-label { color: #cbd5e1; white-space: nowrap; font-weight: bold;}
    .cc-clothes-wrap { display: flex; gap: 6px; flex-wrap: wrap;}

    /* 冰感半透明标签 */
    .cc-cloth-tag {
        background: rgba(192, 132, 252, 0.15); border: 1px solid rgba(192, 132, 252, 0.4);
        padding: 3px 8px; border-radius: 4px; color: var(--eth-light); text-shadow: 0 0 3px rgba(255,255,255,0.2);
    }

    /* 柔和樱花粉高亮内心 */
    .cc-thought {
        background: rgba(244, 114, 182, 0.08); border-left: 2px solid var(--eth-pink);
        padding: 8px 12px; color: var(--eth-pink); font-style: italic; border-radius: 0 6px 6px 0;
        margin-top: 5px; box-shadow: inset 5px 0 15px rgba(244, 114, 182, 0.05);
    }

    /* 绿化度进度条 (直接使用蓝紫仙气流光) */
    .cuckold-meter { margin-top: 10px; border-top: 1px dashed rgba(255,255,255,0.1); padding-top: 12px; }
    .cm-header { display: flex; justify-content: space-between; font-size: 0.8rem; color: #cbd5e1; margin-bottom: 6px;}
    .cm-track { width: 100%; height: 6px; background: rgba(0,0,0,0.5); border-radius: 4px; overflow: hidden; position: relative;}
    .cm-fill {
        height: 100%;
        background: var(--bp-horizontal);
        background-size: 200% 100%;
        animation: gradient-flow 3s linear infinite;
        box-shadow: 0 0 12px var(--eth-purple);
        transition: width 1s cubic-bezier(0.4, 0, 0.2, 1);
    }

</style>
