<body>

<div class="super-system-wrap">

    <!-- 1. 置顶区：浅紫仙气技能键 -->
    <div class="top-command-console">
        <div class="skill-bar">
            <div class="cyber-btn" onclick="toggleCmd(this, '聽令')">聽令</div>
            <div class="cyber-btn" onclick="toggleCmd(this, '達令')">達令</div>
            <div class="cyber-btn" onclick="toggleCmd(this, '綠令')">綠令</div>
            <div class="cyber-btn" onclick="toggleCmd(this, '觀看')">觀看</div>
        </div>
        <!-- 弹出的幻彩输入台 -->
        <div class="input-drawer" id="cmd-drawer">
            <div class="drawer-prefix" id="cmd-prefix">【指令+</div>
            <input type="text" class="drawer-input" id="cmd-args" placeholder="输入：目标对象, 场景设定...">
            <button class="drawer-btn" onclick="fireCmd()">OVERRIDE</button>
        </div>
    </div>

    <!-- 2. 数据迷幻矩阵 (可折叠) -->
    <details class="data-matrix-panel" id="main-matrix" open>
        <summary class="matrix-summary">
            <span class="magic-title">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2L2 7l10 5 10-5-10-5z"></path><path d="M2 17l10 5 10-5"></path><path d="M2 12l10 5 10-5"></path></svg>
                太虚幻境系统 (Psycho Matrix)
            </span>
            <span style="color:var(--eth-light); font-size:0.8rem; font-weight:normal; opacity:0.7;">[点击缩放]</span>
        </summary>

        <div class="rgb-strip" style="height:1px; opacity: 0.8;"></div>

        <div class="panel-body">
            <!-- 贾环自身状态 -->
            <div class="info-cluster">
                <div class="info-tag">
                    <span class="tag-title">时空坐标</span>
                    <span class="tag-val"><span id="zv-date">--</span> / <span id="zv-time">--</span></span>
                </div>
                <div class="info-tag">
                    <span class="tag-title">境域/天象</span>
                    <span class="tag-val"><span id="zv-loc">--</span> | $1</span>
                </div>
                <div class="info-tag">
                    <span class="tag-title">灵壳伪装 (着装)</span>
                    <span class="tag-val" style="color:var(--eth-light);">$2</span>
                </div>
                <!-- 想法高亮特写 -->
                <div class="info-tag thought-tag">
                    <span class="tag-title" style="color:var(--eth-pink);">幽念波频 (内心)</span>
                    <span class="tag-val thought-val">"$3"</span>
                </div>
            </div>

            <!-- 舆情监控 (统一蓝紫渐变) -->
            <div class="rumor-grid">
                <div class="rumor-item"><span class="r-badge">府内</span><span class="r-text">$4</span></div>
                <div class="rumor-item"><span class="r-badge">市井</span><span class="r-text">$5</span></div>
                <div class="rumor-item"><span class="r-badge">禁宫</span><span class="r-text">$6</span></div>
                <div class="rumor-item"><span class="r-badge">天下</span><span class="r-text">$7</span></div>
            </div>

            <!-- 人物深度解析容器 -->
            <div>
                <div class="char-engine-title">
                    <span>◈ 网域角色魂波透析</span>
                    <span style="font-size:0.8rem; color:#cbd5e1; font-weight:normal;">展开卡片查看隐秘数值</span>
                </div>
                <div class="char-grid" id="char-render-zone" data-raw="$8">
                    <!-- JS 解析装载处 -->
                </div>
            </div>

        </div>
    </details>

</div>

<script>
    (function(){
        // ======================================
        // 核心一：四大技能快捷系统 (附带蓝紫流光排他激活)
        // ======================================
        let currentCmd = '';
        let activeBtn = null;
        const drawer = document.getElementById('cmd-drawer');
        const prefix = document.getElementById('cmd-prefix');
        const argInput = document.getElementById('cmd-args');

        window.toggleCmd = function(btnElem, cmdName) {
            if(drawer.classList.contains('active') && currentCmd === cmdName) {
                drawer.classList.remove('active');
                if(activeBtn) activeBtn.classList.remove('active');
                return;
            }
            if(activeBtn) activeBtn.classList.remove('active');
            activeBtn = btnElem;
            activeBtn.classList.add('active');

            drawer.classList.add('active');
            currentCmd = cmdName;
            prefix.innerText = `【${cmdName}+`;
            argInput.focus();
        };

        window.fireCmd = function() {
            const args = argInput.value.trim();
            if(!args) return;
            const finalCommand = `【${currentCmd}+${args}】`;

            if (typeof triggerSlash === 'function') {
                triggerSlash('/send ' + finalCommand + ' | /trigger');
                argInput.value = '';
                drawer.classList.remove('active');
                if(activeBtn) activeBtn.classList.remove('active');
            } else {
                alert('环境未链接。拟发送指令：' + finalCommand);
            }
        };
        argInput.addEventListener('keypress', e => { if(e.key === 'Enter') fireCmd(); });

        // ======================================
        // 核心二：动态解析 AI 吐出的绿楼格式 + 融合 MVU
        // ======================================
        const hasAllVars = typeof getAllVariables === 'function';
        const hasLodash = typeof _ !== 'undefined' && typeof _.get === 'function';
        let mvuVars = {}; if (hasAllVars && hasLodash) mvuVars = getAllVariables();

        if(document.getElementById('zv-date')) {
            document.getElementById('zv-date').innerText = _.get(mvuVars, '日期', '未知');
            document.getElementById('zv-time').innerText = _.get(mvuVars, '时间', '');
            document.getElementById('zv-loc').innerText = _.get(mvuVars, '所在地点', '未知');
        }

        const rawChars = document.getElementById('char-render-zone').getAttribute('data-raw');
        const renderZone = document.getElementById('char-render-zone');
        renderZone.innerHTML = '';

        if(rawChars && rawChars.trim().length > 0) {
            const characters = rawChars.split(' / ');
            const mvuDict = _.get(mvuVars, '人物关系', null) || _.get(mvuVars, 'stat_data.人物关系', {});

            characters.forEach(charRaw => {
                const attrs = charRaw.split(',');
                if(attrs.length < 6) return;

                const name = attrs[0].trim();
                const gender = attrs[1].trim();
                const clothes = attrs[2].trim().split(';');
                const stateDesc = attrs[3].trim();
                const thought = attrs[4].trim();
                const ntrDegree = parseInt(attrs[5].trim()) || 0;

                const mData = mvuDict[name] || {};
                const affinity = _.get(mData, '亲和度', '未探明');
                const threat = _.get(mData, '威胁度', 0);
                const rep = _.get(mData, '公开印象', '无');

                // 蓝紫主题男女标识
                const gIcon = gender === '男' ? '<span class="cc-gender-m">♂</span>' : '<span class="cc-gender-f">♀</span>';
                const clothesHtml = clothes.map(c => `<span class="cc-cloth-tag">${c.trim()}</span>`).join('');

                let cuckoldHtml = '';
                if(gender === '男') {
                    // 男性的绿化进度条，不再变绿，而是跟从主色调“太虚幻紫/星际变异”的蓝紫粉流动变化
                    cuckoldHtml = `
                    <div class="cuckold-meter">
                        <div class="cm-header"><span>☣ 绿化侵蚀率</span><span style="color:var(--eth-pink); font-family:monospace; font-size:1rem; font-weight:bold;">${ntrDegree}%</span></div>
                        <div class="cm-track"><div class="cm-fill" style="width: ${ntrDegree}%;"></div></div>
                    </div>`;
                }

                const cardHtml = `
                <div class="char-card" onclick="this.classList.toggle('expanded')">
                    <div class="cc-head">
                        <span class="cc-name">${name} ${gIcon}</span>
                        <!-- 圆角好感度牌：直接引用绝美渐变 -->
                        <span class="cc-aff-badge">亲和力: ${affinity}</span>
                    </div>
                    <div class="cc-body">
                        <div class="cc-row">
                            <span class="cc-label">着装:</span>
                            <div class="cc-clothes-wrap">${clothesHtml}</div>
                        </div>
                        <div class="cc-row">
                            <span class="cc-label">状态:</span>
                            <span style="color:var(--eth-light);">${stateDesc}</span>
                        </div>
                        <div class="cc-row" style="color:#cbd5e1; font-size:0.8rem; margin-top:2px;">
                            <span class="cc-label" style="font-weight:normal;">隐情:</span>
                            <span>威胁指数 ${threat} | 世评: ${rep}</span>
                        </div>
                        <div class="cc-thought">
                            " ${thought} "
                        </div>
                        ${cuckoldHtml}
                    </div>
                </div>`;

                renderZone.innerHTML += cardHtml;
            });
        }
    })();
</script>
</body>
</html>
```

### 🌸 这一版「浅空幻紫」的极致改变：
1. **绿色彻底消失**：现在您的主色变成了极其通透的 `星空蓝 -- 浅幽紫 -- 樱花粉` 的渐变。所有的光晕发光也由刺眼的强光，收束成了仙气感十足的柔光扩散（Blur Shadow）。
2. **底层面板“通透明亮”**：背景不再是压抑的死黑或深红紫，而是透亮的浅黑蓝紫色，结合磨砂毛玻璃 (`backdrop-filter: blur(25px)`)，界面看起来特别像次世代的大屏科幻游戏。
3. **视觉统一化（蓝紫渐变包场）**：
   - 最上面的按键，默认是浅紫透明边框，点击或悬停时瞬间被“蓝紫粉”绝美渐变充盈整个实体框，质感绝佳。
   - 内部每个舆情标签（情报来源）、人物卡里的「亲和力标签」、甚至是展开后男性专属的「绿化进度条」，**全部应用了该神仙级的蓝粉紫颜色渐变效果**！
4. **七彩炫光RGB微调**：大标题下方以及人物卡片底部悬停时，依然会浮现流动的七彩 RGB 霓虹线。只是这次亮度调整得更为柔和，完美融入了浅紫色的体系之中，不会觉得突兀刺眼。
